create policy teams_read_authenticated on public.teams for select to authenticated using (true);
create policy teams_admin_manage on public.teams for all to authenticated using (public.is_team_member(id, array['admin'])) with check (public.is_team_member(id, array['admin']));
create policy profiles_read_authenticated on public.profiles for select to authenticated using (true);
create policy profiles_update_self on public.profiles for update to authenticated using (id = (select auth.uid())) with check (id = (select auth.uid()));
create policy memberships_read_member on public.team_memberships for select to authenticated using (public.is_team_member(team_id));
create policy memberships_admin_manage on public.team_memberships for all to authenticated using (public.is_team_member(team_id, array['admin'])) with check (public.is_team_member(team_id, array['admin']));
create policy periods_read_authenticated on public.reporting_periods for select to authenticated using (true);
create policy periods_admin_manage on public.reporting_periods for all to authenticated using (exists (select 1 from public.team_memberships where profile_id = (select auth.uid()) and role = 'admin')) with check (exists (select 1 from public.team_memberships where profile_id = (select auth.uid()) and role = 'admin'));
create policy upload_batches_team_read on public.upload_batches for select to authenticated using (public.is_team_member(team_id));
create policy upload_batches_contributor_create on public.upload_batches for insert to authenticated with check (uploaded_by = (select auth.uid()) and public.is_team_member(team_id, array['contributor', 'reviewer', 'admin']));
create policy snapshots_team_read on public.source_snapshots for select to authenticated using (public.is_team_member(team_id));
create policy snapshots_contributor_create on public.source_snapshots for insert to authenticated with check (uploaded_by = (select auth.uid()) and public.is_team_member(team_id, array['contributor', 'reviewer', 'admin']));
create policy selections_team_read on public.source_selections for select to authenticated using (exists (select 1 from public.source_snapshots s where s.id = source_snapshot_id and public.is_team_member(s.team_id)));
create policy selections_admin_manage on public.source_selections for all to authenticated using (exists (select 1 from public.source_snapshots s where s.id = source_snapshot_id and public.is_team_member(s.team_id, array['admin']))) with check (selected_by = (select auth.uid()) and exists (select 1 from public.source_snapshots s where s.id = source_snapshot_id and public.is_team_member(s.team_id, array['admin'])));
create policy runs_team_read on public.reconciliation_runs for select to authenticated using (exists (select 1 from public.reconciliation_run_sources rs join public.source_snapshots s on s.id = rs.source_snapshot_id where rs.reconciliation_run_id = id and public.is_team_member(s.team_id)));
create policy run_sources_team_read on public.reconciliation_run_sources for select to authenticated using (exists (select 1 from public.source_snapshots s where s.id = source_snapshot_id and public.is_team_member(s.team_id)));
create policy normalized_team_read on public.normalized_records for select to authenticated using (exists (select 1 from public.source_snapshots s where s.id = source_snapshot_id and public.is_team_member(s.team_id)));
create policy rules_read_authenticated on public.rules for select to authenticated using (true);
create policy rules_admin_manage on public.rules for all to authenticated using (exists (select 1 from public.team_memberships where profile_id = (select auth.uid()) and role = 'admin')) with check (exists (select 1 from public.team_memberships where profile_id = (select auth.uid()) and role = 'admin'));
create policy rule_versions_read_authenticated on public.rule_versions for select to authenticated using (true);
create policy rule_versions_admin_manage on public.rule_versions for all to authenticated using (exists (select 1 from public.team_memberships where profile_id = (select auth.uid()) and role = 'admin')) with check (created_by = (select auth.uid()) and exists (select 1 from public.team_memberships where profile_id = (select auth.uid()) and role = 'admin'));
create policy mismatches_team_read on public.mismatches for select to authenticated using (exists (select 1 from public.reconciliation_run_sources rs join public.source_snapshots s on s.id = rs.source_snapshot_id where rs.reconciliation_run_id = mismatches.reconciliation_run_id and public.is_team_member(s.team_id)));
create policy mismatches_reviewer_update on public.mismatches for update to authenticated using (exists (select 1 from public.reconciliation_run_sources rs join public.source_snapshots s on s.id = rs.source_snapshot_id where rs.reconciliation_run_id = mismatches.reconciliation_run_id and public.is_team_member(s.team_id, array['reviewer', 'admin']))) with check (exists (select 1 from public.reconciliation_run_sources rs join public.source_snapshots s on s.id = rs.source_snapshot_id where rs.reconciliation_run_id = mismatches.reconciliation_run_id and public.is_team_member(s.team_id, array['reviewer', 'admin'])));
create policy history_team_read on public.mismatch_history for select to authenticated using (exists (select 1 from public.mismatches m join public.reconciliation_run_sources rs on rs.reconciliation_run_id = m.reconciliation_run_id join public.source_snapshots s on s.id = rs.source_snapshot_id where m.id = mismatch_id and public.is_team_member(s.team_id)));
create policy known_read_authenticated on public.known_issues for select to authenticated using (true);
create policy known_admin_manage on public.known_issues for all to authenticated using (exists (select 1 from public.team_memberships where profile_id = (select auth.uid()) and role = 'admin')) with check (created_by = (select auth.uid()) and exists (select 1 from public.team_memberships where profile_id = (select auth.uid()) and role = 'admin'));
create policy drafts_team_read on public.psi_drafts for select to authenticated using (exists (select 1 from public.reconciliation_run_sources rs join public.source_snapshots s on s.id = rs.source_snapshot_id where rs.reconciliation_run_id = psi_drafts.reconciliation_run_id and public.is_team_member(s.team_id)));
create policy drafts_contributor_create on public.psi_drafts for insert to authenticated with check (created_by = (select auth.uid()) and exists (select 1 from public.reconciliation_run_sources rs join public.source_snapshots s on s.id = rs.source_snapshot_id where rs.reconciliation_run_id = reconciliation_run_id and public.is_team_member(s.team_id, array['contributor', 'reviewer', 'admin'])));
create policy drafts_reviewer_approve on public.psi_drafts for update to authenticated using (exists (select 1 from public.reconciliation_run_sources rs join public.source_snapshots s on s.id = rs.source_snapshot_id where rs.reconciliation_run_id = psi_drafts.reconciliation_run_id and public.is_team_member(s.team_id, array['reviewer', 'admin']))) with check (approved_by is null or approved_by = (select auth.uid()));
create policy draft_sources_read_authenticated on public.draft_sources for select to authenticated using (exists (select 1 from public.psi_drafts d join public.reconciliation_run_sources rs on rs.reconciliation_run_id = d.reconciliation_run_id join public.source_snapshots s on s.id = rs.source_snapshot_id where d.id = draft_id and public.is_team_member(s.team_id)));
create policy releases_read_authenticated on public.psi_releases for select to authenticated using (true);
create policy release_sources_read_authenticated on public.release_sources for select to authenticated using (true);

revoke insert, update, delete on public.mismatch_history from anon, authenticated;
revoke insert, update, delete on public.activity_logs from anon, authenticated;
